package com.hogaria.config; import org.springframework.context.annotation.*; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.web.SecurityFilterChain; @Configuration public class SecurityConfig { @Bean SecurityFilterChain filterChain(HttpSecurity http) throws Exception { http.csrf(c->c.disable()).authorizeHttpRequests(a->a.requestMatchers("/swagger-ui/**","/v3/api-docs/**").permitAll().anyRequest().permitAll()); return http.build(); }}
